const assets = $('List All Assets').first().json.assets || [];
const stories = $('List All Stories').first().json.stories || [];

// Collect all asset URLs referenced in story content
const referencedUrls = new Set();

function extractUrls(obj) {
  if (!obj || typeof obj !== 'object') return;
  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'string' && value.includes('a.storyblok.com')) {
      referencedUrls.add(value.split('?')[0]); // strip query params
    } else if (typeof value === 'object') {
      extractUrls(value);
    }
  }
}

for (const story of stories) {
  extractUrls(story.content);
}

// Find unused assets (in Storyblok but not referenced in any story)
const unusedAssets = assets.filter(asset => {
  const assetUrl = (asset.filename || '').split('?')[0];
  return !referencedUrls.has(assetUrl);
});

// Find broken references (URLs in stories that don't match any asset)
const assetUrls = new Set(assets.map(a => (a.filename || '').split('?')[0]));
const brokenRefs = [];
for (const url of referencedUrls) {
  if (!assetUrls.has(url)) {
    brokenRefs.push(url);
  }
}

return [{
  json: {
    totalAssets: assets.length,
    totalStories: stories.length,
    referencedAssets: referencedUrls.size,
    unusedAssets: unusedAssets.map(a => ({ filename: a.filename, id: a.id, alt: a.alt })),
    unusedCount: unusedAssets.length,
    brokenReferences: brokenRefs,
    brokenCount: brokenRefs.length,
    summary: `${unusedAssets.length} unused assets, ${brokenRefs.length} broken references out of ${assets.length} total assets across ${stories.length} stories`
  }
}];

